.darma-loader-loading-io-08 {
  display: inline-block;
  width: 61px;
  height: 61px;
  border-radius: 50%;
  border: 5px solid color-mix(in srgb, var(--loader-secondary-color, #fecaca) 35%, transparent);
  border-top-color: var(--loader-color, #ef4444);
  border-right-color: var(--loader-color, #ef4444);
  animation: darma-loader-loading-io-08-spin 0.85s cubic-bezier(.55,.15,.45,.85) infinite;
}
.darma-loader-loading-io-08::after {
  content: "";
  display: block;
  width: calc(100% - 16px);
  height: calc(100% - 16px);
  margin: 4px;
  border-radius: 50%;
  border: 4px solid transparent;
  border-bottom-color: var(--loader-secondary-color, #fecaca);
  animation: darma-loader-loading-io-08-spin 0.59s linear infinite reverse;
}
@keyframes darma-loader-loading-io-08-spin { to { transform: rotate(360deg); } }

